import streamlit as st
from api_client import login, register

# ── PAGE CONFIG ──────────────────────────────────────────
st.set_page_config(
    page_title="BI Dashboard",
    page_icon="📊",
    layout="wide",
    initial_sidebar_state="expanded"
)





# ── HIDE STREAMLIT CHROME ────────────────────────────────
